API测试是软件开发过程中非常重要的一环，它可以有效检测API的正确性、准确性和健壮性，提高软件的可靠性和性能。下面是一段数字视频处理中pipeline的API测试代码，用于测试pipeline的启动和停止过程是否正确。

```
#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>

#include "pipeline.h"

void on_start_test(pipeline_t* pipeline, void* user_data);
void on_stop_test(pipeline_t* pipeline, void* user_data);

int main(int argc, char** argv) {
    // 创建pipeline对象
    pipeline_t* pipeline = pipeline_create();
    if (!pipeline) {
        printf("Failed to create pipeline\n");
        return EXIT_FAILURE;
    }

    // 设置回调函数
    pipeline_set_on_start(pipeline, on_start_test);
    pipeline_set_on_stop(pipeline, on_stop_test);

    // 启动pipeline
    if (!pipeline_start(pipeline)) {
        printf("Failed to start pipeline\n");
        pipeline_destroy(pipeline);
        return EXIT_FAILURE;
    }

    // 等待3秒
    sleep(3);

    // 停止pipeline
    pipeline_stop(pipeline);

    // 销毁pipeline对象
    pipeline_destroy(pipeline);

    return EXIT_SUCCESS;
}

// pipeline启动测试回调函数
void on_start_test(pipeline_t* pipeline, void* user_data) {
    printf("Pipeline started successfully\n");

    // 这里可以添加其他测试代码
}

// pipeline停止测试回调函数
void on_stop_test(pipeline_t* pipeline, void* user_data) {
    printf("Pipeline stopped successfully\n");

    // 这里可以添加其他测试代码
}
```

上述代码中，我们首先创建了pipeline对象，并设置了启动和停止时的回调函数。然后我们调用pipeline_start启动pipeline，并用sleep函数等待3秒，然后调用pipeline_stop停止pipeline。最后销毁pipeline对象。

在启动和停止过程中，回调函数将会被自动调用，用于检测pipeline的正确性。在回调函数中，我们可以添加其他测试代码，以对pipeline的不同功能和特性进行测试。

将API封装成一个lib库是一个非常常见的软件开发流程。测试这个lib库的方法也很简单，可以使用类似于单元测试的方法进行测试。下面是一个使用CUnit测试库进行lib库的API测试的例子：

假设我们的lib库是一个计算器的API，提供加、减、乘、除等基本四则运算。我们需要编写API测试用例来测试这个库的API。

```
#include <stdio.h>
#include <stdlib.h>
#include <CUnit/CUnit.h>
#include <CUnit/Basic.h>

#include "calculator.h" // 假设这个头文件中包含了我们的API

void test_addition(void);
void test_subtraction(void);
void test_multiplication(void);
void test_division(void);

int main() {
    CU_initialize_registry();
    CU_pSuite suite = CU_add_suite("Calculator Test Suite", NULL, NULL);
    CU_add_test(suite, "Addition Test", test_addition);
    CU_add_test(suite, "Subtraction Test", test_subtraction);
    CU_add_test(suite, "Multiplication Test", test_multiplication);
    CU_add_test(suite, "Division Test", test_division);

    // 运行测试
    CU_basic_set_mode(CU_BRM_VERBOSE);
    CU_basic_run_tests();
    CU_cleanup_registry();

    return CU_get_error();
}

void test_addition(void) {
    CU_ASSERT_DOUBLE_EQUAL(addition(1.0, 2.0), 3.0, 0.0001);
    CU_ASSERT_DOUBLE_EQUAL(addition(-1.0, 2.0), 1.0, 0.0001);
    CU_ASSERT_DOUBLE_EQUAL(addition(3.1415926, 1.41421356), 4.5558, 0.0001);
}

void test_subtraction(void) {
    CU_ASSERT_DOUBLE_EQUAL(subtraction(1.0, 2.0), -1.0, 0.0001);
    CU_ASSERT_DOUBLE_EQUAL(subtraction(-1.0, 2.0), -3.0, 0.0001);
    CU_ASSERT_DOUBLE_EQUAL(subtraction(3.1415926, 1.41421356), 1.7274, 0.0001);
}

void test_multiplication(void) {
    CU_ASSERT_DOUBLE_EQUAL(multiplication(2.0, 3.0), 6.0, 0.0001);
    CU_ASSERT_DOUBLE_EQUAL(multiplication(-1.0, 2.0), -2.0, 0.0001);
    CU_ASSERT_DOUBLE_EQUAL(multiplication(3.1415926, 1.41421356), 4.4431, 0.0001);
}

void test_division(void) {
    CU_ASSERT_DOUBLE_EQUAL(division(6.0, 2.0), 3.0, 0.0001);
    CU_ASSERT_DOUBLE_EQUAL(division(-2.0, 2.0), -1.0, 0.0001);
    CU_ASSERT_DOUBLE_EQUAL(division(3.1415926, 1.41421356), 2.2271, 0.0001);
}
```

在上面的例子中，我们使用了CUnit这个测试框架。首先我们初始化测试框架，然后添加测试套件，再添加各种测试用例。在测试用例中，我们调用了lib库中的API，并使用CU_ASSERT_DOUBLE_EQUAL宏函数进行测试断言。最后我们运行测试并输出结果。

当运行测试时，框架将自动调用各种测试用例并输出其结果。如果测试用例未通过，将输出错误信息。根据测试结果，我们可以修复代码中的错误，以确保我们的API能够正常工作。
